   348→        }
   349→
   350→        // Don't retry if we've exhausted attempts
   351→        if (attempt > maxRetries) {
   352→          throw error;
   353→        }
   354→
   355→        // Exponential backoff with jitter (reduced for testing)
   356→        const delay = retryDelayMs * Math.pow(2, attempt - 1) + Math.random() * 100;
   357→        await this.sleep(delay);
   358→      }
   359→    }
   360→
   361→    throw lastError;
   362→  }
