   464→  private async fetchMessageDetails(
   465→    messages: gmail_v1.Schema$Message[],
   466→    format: string,
   467→    batchSize: number,
   468→    continueOnError: boolean,
   469→    errors: FetchError[]
   470→  ): Promise<EmailMessage[]> {
   471→    const emails: EmailMessage[] = [];
   472→
   473→    // Process in batches to avoid overwhelming the API
   474→    for (let i = 0; i < messages.length; i += batchSize) {
   475→      const batch = messages.slice(i, i + batchSize);
   476→      const batchPromises = batch.map(async (msg) => {
   477→        // Validate message ID
