   493→          return this.parseGmailMessage(message);
   494→        } catch (error) {
   495→          const err = error as Error & { code?: string | number };
   496→          const errorMessage = err.message || 'Unknown error';
   497→
   498→          errors.push({
   499→            messageId: msg.id,
   500→            error: errorMessage,
   501→            errorCode: err.code,
