     1→/**
     2→ * Gmail Email Fetcher with Pagination
     3→ *
     4→ * Provides robust email fetching capabilities with pagination, batch processing,
     5→ * error recovery, and Gmail API response parsing.
     6→ *
     7→ * ## Page vs Batch Distinction
     8→ *
     9→ * This module uses two levels of chunking for optimal performance:
    10→ *
    11→ * ### Pages (Gmail API Level)
    12→ * - A **page** is a set of message references (IDs) returned by Gmail's `list()` API
    13→ * - Contains only metadata (message ID, thread ID), not full email content
    14→ * - Size controlled by `maxResults` option (default: 100)
    15→ * - Gmail returns `nextPageToken` when more pages are available
    16→ * - Used for **pagination** through large result sets (e.g., 10,000 emails)
    17→ *
    18→ * ### Batches (Implementation Level)
    19→ * - A **batch** is our internal grouping for fetching full message details
    20→ * - After getting a page of IDs, we call `get()` for each to retrieve full content
    21→ * - Instead of fetching all simultaneously, we split into smaller batches
    22→ * - Size controlled by `batchSize` option (default: 10)
    23→ * - Batches are processed **in parallel** using `Promise.all()`
    24→ * - Prevents overwhelming the Gmail API with hundreds of concurrent requests
    25→ *
    26→ * ### Example Flow
    27→ * ```
    28→ * 1. Gmail API list() → Page 1: [msg1...msg100]      (maxResults=100)
    29→ *    ↓
    30→ * 2. Split into batches:
    31→ *    - Batch 1: [msg1...msg10]                       (batchSize=10)
    32→ *    - Batch 2: [msg11...msg20]
    33→ *    - ...
    34→ *    - Batch 10: [msg91...msg100]
    35→ *    ↓
    36→ * 3. Process each batch with Promise.all() for parallel fetching
    37→ *    ↓
    38→ * 4. If nextPageToken exists → fetch Page 2 and repeat
    39→ * ```
    40→ *
    41→ * This two-level approach balances Gmail API limits, network efficiency,
    42→ * and rate limiting while maintaining optimal performance.
    43→ *
    44→ * @packageDocumentation
    45→ */
    46→
    47→import { gmail_v1 } from 'googleapis';
    48→import { parseOneAddress, parseAddressList } from 'email-addresses';
    49→import { GmailClient } from './gmail-client';
    50→
    51→/**
    52→ * Email address representation
    53→ */
    54→export interface EmailAddress {
    55→  /**
    56→   * Email address
    57→   */
    58→  email: string;
    59→
    60→  /**
    61→   * Display name (if available)
    62→   */
    63→  name?: string;
    64→
    65→  /**
    66→   * Raw header value for debugging
    67→   */
    68→  raw: string;
    69→}
    70→
    71→/**
    72→ * Email message structure matching Gmail API payload
    73→ */
    74→export interface EmailMessage {
    75→  /**
    76→   * Gmail message ID
    77→   */
    78→  id: string;
    79→
    80→  /**
    81→   * Gmail thread ID
    82→   */
    83→  threadId: string;
    84→
    85→  /**
    86→   * Original Gmail labels
    87→   */
    88→  gmailLabels: string[];
    89→
    90→  /**
    91→   * Gmail API payload structure
    92→   */
    93→  payload?: gmail_v1.Schema$MessagePart;
    94→
    95→  /**
    96→   * Extracted subject
    97→   */
    98→  subject?: string;
    99→
   100→  /**
   101→   * Parsed from address
   102→   */
   103→  from?: EmailAddress;
   104→
   105→  /**
   106→   * Parsed to addresses
   107→   */
   108→  to?: EmailAddress[];
   109→
   110→  /**
   111→   * Parsed cc addresses
   112→   */
   113→  cc?: EmailAddress[];
   114→
   115→  /**
   116→   * Parsed bcc addresses
   117→   */
   118→  bcc?: EmailAddress[];
   119→
   120→  /**
   121→   * Parsed date
   122→   */
   123→  date?: Date;
   124→
   125→  /**
   126→   * Gmail-generated snippet
   127→   */
   128→  snippet?: string;
   129→
   130→  /**
   131→   * History ID
   132→   */
   133→  historyId?: string;
   134→
   135→  /**
   136→   * Size estimate
   137→   */
   138→  sizeEstimate?: number;
   139→
   140→  /**
   141→   * Internal date (milliseconds since epoch)
   142→   */
   143→  internalDate?: string;
   144→
   145→  /**
   146→   * Plain text body (extracted from payload)
   147→   */
   148→  bodyPlain?: string;
   149→
   150→  /**
   151→   * HTML body (extracted from payload)
   152→   */
   153→  bodyHtml?: string;
   154→
   155→  /**
   156→   * Processing metadata
   157→   */
   158→  isProcessed?: boolean;
   159→  processedAt?: Date;
   160→  processingSessionId?: string;
   161→  processingBatch?: string;
   162→  processingPriority?: number;
   163→}
   164→
   165→/**
   166→ * Options for fetching emails
   167→ */
   168→export interface FetchEmailsOptions {
   169→  /**
   170→   * Maximum number of emails to fetch per page
   171→   * @default 100
   172→   */
   173→  maxResults?: number;
   174→
   175→  /**
   176→   * Gmail search query filter
   177→   */
   178→  query?: string;
   179→
   180→  /**
   181→   * Label IDs to filter by
   182→   */
   183→  labelIds?: string[];
   184→
   185→  /**
   186→   * Page token for pagination
   187→   */
   188→  pageToken?: string;
   189→
   190→  /**
   191→   * Fetch all pages (ignores maxResults for total, but uses it per page)
   192→   * @default false
   193→   */
   194→  fetchAll?: boolean;
   195→
   196→  /**
   197→   * Maximum total emails to fetch (safety limit for fetchAll)
   198→   * Prevents memory exhaustion when fetching large mailboxes
   199→   * @default 10000
   200→   */
   201→  maxTotalEmails?: number;
   202→
   203→  /**
   204→   * Message format (full, minimal, metadata, raw)
   205→   * @default 'full'
   206→   */
   207→  format?: 'full' | 'minimal' | 'metadata' | 'raw';
   208→
   209→  /**
   210→   * Batch size for fetching message details
   211→   * @default 10
   212→   */
   213→  batchSize?: number;
   214→
   215→  /**
   216→   * Continue fetching on individual message errors
   217→   * @default true
   218→   */
   219→  continueOnError?: boolean;
