   222→/**
   223→ * Fetch error details
   224→ */
   225→export interface FetchError {
   226→  /**
   227→   * Message ID that failed
   228→   */
   229→  messageId: string;
   230→
   231→  /**
   232→   * Error message
   233→   */
   234→  error: string;
   235→
   236→  /**
   237→   * Gmail API error code (if available)
   238→   */
   239→  errorCode?: string | number;
   240→
   241→  /**
   242→   * Stack trace for debugging (only in development)
   243→   */
   244→  stackTrace?: string;
   245→
   246→  /**
   247→   * Timestamp of error
   248→   */
   249→  timestamp: Date;
   250→}
   251→
   252→/**
   253→ * Result of email fetch operation
   254→ */
   255→export interface FetchEmailsResult {
   256→  /**
   257→   * Fetched emails
   258→   */
   259→  emails: EmailMessage[];
   260→
   261→  /**
   262→   * Total number of emails fetched
   263→   */
   264→  totalFetched: number;
   265→
   266→  /**
   267→   * Whether there are more emails to fetch
   268→   */
   269→  hasMore: boolean;
   270→
   271→  /**
   272→   * Next page token (if hasMore is true)
   273→   */
   274→  nextPageToken?: string;
   275→
   276→  /**
   277→   * Errors encountered during fetch
   278→   */
   279→  errors: FetchError[];
   280→
   281→  /**
   282→   * Fetch operation duration in milliseconds
   283→   */
   284→  durationMs: number;
   285→}
   286→
   287→/**
   288→ * Gmail email fetcher with pagination and batch processing
   289→ *
   290→ * Handles pagination, batch fetching of message details, error recovery,
   291→ * and Gmail API response parsing.
   292→ *
   293→ * @example
   294→ * ```typescript
   295→ * const client = new GmailClient(credentials);
   296→ * const fetcher = new EmailFetcher(client);
   297→ *
   298→ * // Fetch first page of unread emails
   299→ * const result = await fetcher.fetchEmails({
   300→ *   query: 'is:unread',
   301→ *   maxResults: 50
   302→ * });
   303→ *
   304→ * // Fetch next page
   305→ * if (result.hasMore) {
   306→ *   const nextPage = await fetcher.fetchEmails({
   307→ *     pageToken: result.nextPageToken
   308→ *   });
   309→ * }
   310→ *
   311→ * // Fetch all emails
   312→ * const allEmails = await fetcher.fetchEmails({
   313→ *   query: 'label:inbox',
   314→ *   fetchAll: true
   315→ * });
   316→ * ```
   317→ */
   318→export class EmailFetcher {
   319→  /**
   320→   * Creates a new email fetcher
   321→   *
   322→   * @param gmailClient - Authenticated Gmail client
   323→   */
   324→  constructor(private readonly gmailClient: GmailClient) {
   325→    // Store full client to leverage retry logic and auth management
   326→  }
   327→
   328→  /**
   329→   * Fetch emails with pagination support
   330→   *
   331→   * @param options - Fetch options
   332→   * @returns Fetch result with emails and pagination info
   333→   */
   334→  async fetchEmails(options: FetchEmailsOptions = {}): Promise<FetchEmailsResult> {
   335→    const startTime = Date.now();
   336→    const {
   337→      maxResults = 100,
   338→      query,
   339→      labelIds,
   340→      pageToken,
   341→      fetchAll = false,
   342→      maxTotalEmails = 10000,
   343→      format = 'full',
   344→      batchSize = 10,
   345→      continueOnError = true,
   346→    } = options;
   347→
   348→    console.log('Starting email fetch', {
   349→      maxResults,
   350→      query: query || 'none',
   351→      labelIds: labelIds || 'none',
   352→      fetchAll,
   353→      maxTotalEmails,
   354→      format,
   355→      batchSize,
   356→    });
   357→
   358→    const allEmails: EmailMessage[] = [];
   359→    const allErrors: FetchError[] = [];
   360→    let currentPageToken: string | undefined = pageToken;
   361→    let hasMore = false;
   362→    let pageCount = 0;
   363→    let hitSafetyLimit = false;
   364→
   365→    do {
   366→      pageCount++;
   367→
   368→      // Check safety limit before fetching next page
   369→      if (allEmails.length >= maxTotalEmails) {
   370→        console.warn(`Reached maxTotalEmails limit (${maxTotalEmails}), stopping fetch`);
   371→        hitSafetyLimit = true;
   372→        hasMore = true; // There may be more, but we're stopping
   373→        break;
   374→      }
   375→
   376→      console.debug(`Fetching page ${pageCount}, pageToken: ${currentPageToken || 'none'}`);
   377→
   378→      // Fetch message list using GmailClient (with built-in retry logic)
   379→      const listParams: gmail_v1.Params$Resource$Users$Messages$List = {
   380→        maxResults,
   381→      };
   382→
   383→      if (query) {
   384→        listParams.q = query;
   385→      }
   386→
   387→      if (labelIds && labelIds.length > 0) {
   388→        listParams.labelIds = labelIds;
   389→      }
   390→
   391→      if (currentPageToken) {
   392→        listParams.pageToken = currentPageToken;
   393→      }
   394→
   395→      const listResponse = await this.gmailClient.listMessages(listParams, {
   396→        retryOnRateLimit: true,
   397→        maxRetries: 3,
   398→      });
   399→      const messages = listResponse.messages || [];
   400→
   401→      console.log(`Page ${pageCount}: Found ${messages.length} messages`);
   402→
   403→      // Fetch message details in batches
   404→      const emails = await this.fetchMessageDetails(messages, format, batchSize, continueOnError, allErrors);
   405→      allEmails.push(...emails);
   406→
   407→      console.debug(`Page ${pageCount}: Successfully fetched ${emails.length} emails`);
   408→
   409→      // Check for more pages
   410→      currentPageToken = listResponse.nextPageToken || undefined;
   411→      hasMore = !!currentPageToken;
   412→    } while (fetchAll && hasMore);
   413→
   414→    const durationMs = Date.now() - startTime;
   415→
   416→    console.log('Email fetch completed', {
   417→      totalFetched: allEmails.length,
   418→      errors: allErrors.length,
   419→      durationMs,
   420→      hasMore: !fetchAll && hasMore,
   421→      pagesProcessed: pageCount,
   422→    });
   423→
   424→    return {
   425→      emails: allEmails,
   426→      totalFetched: allEmails.length,
   427→      hasMore: hitSafetyLimit ? true : !fetchAll && hasMore,
   428→      nextPageToken: !fetchAll ? currentPageToken : undefined,
   429→      errors: allErrors,
   430→      durationMs,
   431→    };
   432→  }
   433→
   434→  /**
   435→   * Fetch single email by ID
   436→   *
   437→   * @param messageId - Gmail message ID
   438→   * @param format - Message format
   439→   * @returns Email message
   440→   */
   441→  async fetchEmailById(
   442→    messageId: string,
   443→    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full'
   444→  ): Promise<EmailMessage> {
   445→    const message = await this.gmailClient.getMessage(messageId, format, {
   446→      retryOnRateLimit: true,
   447→      maxRetries: 3,
   448→    });
   449→
   450→    return this.parseGmailMessage(message);
   451→  }
   452→
   453→  /**
   454→   * Fetch message details in batches
   455→   *
   456→   * @param messages - Message references from list API
   457→   * @param format - Message format
   458→   * @param batchSize - Number of messages to fetch concurrently
   459→   * @param continueOnError - Whether to continue on individual errors
   460→   * @param errors - Array to collect errors
   461→   * @returns Fetched email messages
   462→   * @private
   463→   */
   464→  private async fetchMessageDetails(
   465→    messages: gmail_v1.Schema$Message[],
   466→    format: string,
   467→    batchSize: number,
   468→    continueOnError: boolean,
   469→    errors: FetchError[]
   470→  ): Promise<EmailMessage[]> {
   471→    const emails: EmailMessage[] = [];
   472→
   473→    // Process in batches to avoid overwhelming the API
   474→    for (let i = 0; i < messages.length; i += batchSize) {
   475→      const batch = messages.slice(i, i + batchSize);
   476→      const batchPromises = batch.map(async (msg) => {
   477→        // Validate message ID
   478→        if (!msg.id) {
   479→          console.error('Message missing ID:', msg);
   480→          errors.push({
   481→            messageId: 'unknown',
   482→            error: 'Message missing ID from Gmail API',
   483→            timestamp: new Date(),
   484→          });
   485→          return null;
   486→        }
   487→
   488→        try {
   489→          const message = await this.gmailClient.getMessage(msg.id, format as 'full' | 'minimal' | 'metadata' | 'raw', {
   490→            retryOnRateLimit: true,
   491→            maxRetries: 3,
   492→          });
   493→          return this.parseGmailMessage(message);
   494→        } catch (error) {
   495→          const err = error as Error & { code?: string | number };
   496→          const errorMessage = err.message || 'Unknown error';
   497→
   498→          errors.push({
   499→            messageId: msg.id,
   500→            error: errorMessage,
   501→            errorCode: err.code,
   502→            stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
   503→            timestamp: new Date(),
   504→          });
   505→
   506→          console.error(`Failed to fetch message ${msg.id}:`, err);
   507→
   508→          if (!continueOnError) {
   509→            throw error;
   510→          }
   511→
   512→          return null;
   513→        }
   514→      });
   515→
   516→      const batchResults = await Promise.all(batchPromises);
   517→      const validEmails = batchResults.filter((email): email is EmailMessage => email !== null);
   518→      emails.push(...validEmails);
   519→    }
   520→
   521→    return emails;
   522→  }
   523→
   524→  /**
   525→   * Parse Gmail API message into EmailMessage format
   526→   *
   527→   * @param message - Gmail API message
   528→   * @returns Parsed email message
   529→   * @throws Error if message is missing required id or threadId
   530→   * @private
   531→   */
   532→  private parseGmailMessage(message: gmail_v1.Schema$Message): EmailMessage {
   533→    // Validate required fields
   534→    if (!message.id) {
   535→      throw new Error('Gmail message missing required id field');
   536→    }
   537→    if (!message.threadId) {
   538→      throw new Error('Gmail message missing required threadId field');
   539→    }
   540→
   541→    const email: EmailMessage = {
   542→      id: message.id,
   543→      threadId: message.threadId,
   544→      gmailLabels: message.labelIds || [],
   545→      snippet: message.snippet || undefined,
   546→      historyId: message.historyId || undefined,
   547→      sizeEstimate: message.sizeEstimate || undefined,
   548→      internalDate: message.internalDate || undefined,
   549→    };
   550→
   551→    // Parse payload if available
   552→    if (message.payload) {
   553→      email.payload = message.payload;
   554→
   555→      // Extract headers
   556→      const headers = message.payload.headers || [];
   557→      email.subject = this.getHeader(headers, 'Subject');
   558→      email.from = this.parseEmailAddress(this.getHeader(headers, 'From'));
   559→      email.to = this.parseEmailAddressList(this.getHeader(headers, 'To'));
   560→      email.cc = this.parseEmailAddressList(this.getHeader(headers, 'Cc'));
   561→      email.bcc = this.parseEmailAddressList(this.getHeader(headers, 'Bcc'));
   562→
   563→      // Parse date
   564→      const dateHeader = this.getHeader(headers, 'Date');
   565→      if (dateHeader) {
   566→        try {
   567→          const parsedDate = new Date(dateHeader);
   568→          // Validate that the date is valid
   569→          if (!isNaN(parsedDate.getTime())) {
   570→            email.date = parsedDate;
   571→          } else {
   572→            console.warn(`Invalid date header: ${dateHeader}`);
   573→          }
   574→        } catch (error) {
   575→          console.error(`Date parsing error for: ${dateHeader}`, error);
   576→        }
   577→      }
   578→
   579→      // Extract body content
   580→      this.extractBodyContent(message.payload, email);
   581→    }
   582→
   583→    return email;
   584→  }
   585→
   586→  /**
   587→   * Get header value by name
   588→   *
   589→   * @param headers - Email headers
   590→   * @param name - Header name
   591→   * @returns Header value or undefined
   592→   * @private
   593→   */
   594→  private getHeader(headers: gmail_v1.Schema$MessagePartHeader[], name: string): string | undefined {
   595→    const header = headers.find((h) => h.name?.toLowerCase() === name.toLowerCase());
   596→    return header?.value || undefined;
   597→  }
   598→
   599→  /**
   600→   * Parse email address from header value using RFC-compliant parser
   601→   *
   602→   * @param headerValue - Header value
   603→   * @returns Parsed email address or undefined
   604→   * @private
   605→   */
   606→  private parseEmailAddress(headerValue?: string): EmailAddress | undefined {
   607→    if (!headerValue) {
   608→      return undefined;
   609→    }
   610→
   611→    try {
   612→      const parsed = parseOneAddress(headerValue);
   613→      if (!parsed || parsed.type !== 'mailbox') {
   614→        console.warn(`Invalid email address format: ${headerValue}`);
   615→        return undefined;
   616→      }
   617→
   618→      return {
   619→        email: parsed.address,
   620→        name: parsed.name || undefined,
   621→        raw: headerValue,
   622→      };
   623→    } catch (error) {
   624→      console.error(`Email parsing failed for: ${headerValue}`, error);
   625→      return undefined;
   626→    }
   627→  }
   628→
   629→  /**
   630→   * Parse comma-separated email address list using RFC-compliant parser
   631→   *
   632→   * @param headerValue - Header value with comma-separated addresses
   633→   * @returns Array of parsed email addresses
   634→   * @private
   635→   */
   636→  private parseEmailAddressList(headerValue?: string): EmailAddress[] | undefined {
   637→    if (!headerValue) {
   638→      return undefined;
   639→    }
   640→
   641→    try {
   642→      const parsed = parseAddressList(headerValue);
   643→      if (!parsed) {
   644→        console.warn(`Invalid email address list: ${headerValue}`);
   645→        return undefined;
   646→      }
   647→
   648→      const addresses = parsed
   649→        .filter((addr) => addr.type === 'mailbox')
   650→        .map((addr) => ({
   651→          email: addr.address,
   652→          name: addr.name || undefined,
   653→          raw: headerValue,
   654→        }));
   655→
   656→      return addresses.length > 0 ? addresses : undefined;
   657→    } catch (error) {
   658→      console.error(`Email list parsing failed for: ${headerValue}`, error);
   659→      return undefined;
   660→    }
   661→  }
   662→
   663→  /**
   664→   * Extract body content from message payload with error handling
   665→   *
   666→   * @param part - Message part
   667→   * @param email - Email message to populate
   668→   * @private
   669→   */
   670→  private extractBodyContent(part: gmail_v1.Schema$MessagePart, email: EmailMessage): void {
   671→    // Check if this part has body data
   672→    if (part.body?.data) {
   673→      try {
   674→        const decodedData = Buffer.from(part.body.data, 'base64').toString('utf-8');
   675→
   676→        if (part.mimeType === 'text/plain') {
   677→          email.bodyPlain = decodedData;
   678→        } else if (part.mimeType === 'text/html') {
   679→          email.bodyHtml = decodedData;
   680→        }
   681→      } catch (error) {
   682→        console.error(`Failed to decode body for mimeType ${part.mimeType}:`, error);
   683→        // Continue processing other parts
   684→      }
   685→    }
   686→
   687→    // Recursively process nested parts
   688→    if (part.parts) {
   689→      for (const subPart of part.parts) {
   690→        this.extractBodyContent(subPart, email);
   691→      }
   692→    }
   693→  }
   694→}
